class Solution:
    def findMissingAndRepeatedValues(self, grid):
        n = len(grid)
        m = n * n
        count = [0] * (m + 1)
        for row in grid:
            for v in row:
                count[v] += 1
        repeated = missing = 0
        for x in range(1, m + 1):
            if count[x] == 2:
                repeated = x
            elif count[x] == 0:
                missing = x
        return [repeated, missing]

