var findMissingAndRepeatedValues = function(grid) {
    const n = grid.length;
    const m = n * n;
    const count = new Array(m + 1).fill(0);
    for (const row of grid) for (const v of row) count[v]++;
    let repeated = 0, missing = 0;
    for (let x = 1; x <= m; x++) {
        if (count[x] === 2) repeated = x;
        else if (count[x] === 0) missing = x;
    }
    return [repeated, missing];
};
